import React, { useState } from "react";
import { submitReport } from "../services/api";

const BINS = [
  "BIN001","BIN002","BIN003","BIN004","BIN005",
  "BIN006","BIN007","BIN008","BIN009","BIN010",
  "BIN011","BIN012","BIN013","BIN014","BIN015",
  "BIN016","BIN017","BIN018","BIN019","BIN020",
  "BIN021","BIN022","BIN023","BIN024","BIN025",
  "BIN026","BIN027","BIN028","BIN029","BIN030"
];

export default function ReportForm() {
  const [form, setForm]       = useState({ bin_id: "BIN001", reporter: "", message: "", phone: "", fill_level: 80 });
  const [status, setStatus]   = useState(null);
  const [loading, setLoading] = useState(false);

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = () => {
    if (!form.reporter || !form.message) {
      setStatus({ type: "error", text: "Please fill in your name and message." });
      return;
    }
    setLoading(true);
    submitReport({ ...form, fill_level: parseFloat(form.fill_level) })
      .then(res => {
        setStatus({ type: "success", text: `✅ ${res.data.message} (${res.data.report_id})` });
        setForm({ bin_id: "BIN001", reporter: "", message: "", phone: "", fill_level: 80 });
        setLoading(false);
      })
      .catch(() => {
        setStatus({ type: "error", text: "❌ Failed to submit report." });
        setLoading(false);
      });
  };

  const inputStyle = {
    width: "100%", padding: "10px 14px", borderRadius: "8px",
    border: "1px solid #ccc", fontSize: "14px", marginBottom: "16px",
    boxSizing: "border-box"
  };

  return (
    <div>
      <h2 style={{ marginTop: 0, color: "#1a5276" }}>📱 Community Waste Report</h2>
      <p style={{ color: "#666", marginBottom: "24px" }}>
        Simulate an SMS/WhatsApp report from a community member in Buea.
      </p>

      <div style={{ background: "white", borderRadius: "12px", padding: "28px", maxWidth: "560px", boxShadow: "0 2px 8px rgba(0,0,0,0.1)" }}>

        <label style={{ fontWeight: "bold", display: "block", marginBottom: "6px" }}>Select Bin</label>
        <select name="bin_id" value={form.bin_id} onChange={handleChange} style={inputStyle}>
          {BINS.map(b => <option key={b} value={b}>{b}</option>)}
        </select>

        <label style={{ fontWeight: "bold", display: "block", marginBottom: "6px" }}>Your Name</label>
        <input name="reporter" value={form.reporter} onChange={handleChange} placeholder="e.g. Amara Njoku" style={inputStyle} />

        <label style={{ fontWeight: "bold", display: "block", marginBottom: "6px" }}>Phone (optional)</label>
        <input name="phone" value={form.phone} onChange={handleChange} placeholder="+237 6XX XXX XXX" style={inputStyle} />

        <label style={{ fontWeight: "bold", display: "block", marginBottom: "6px" }}>Message</label>
        <textarea name="message" value={form.message} onChange={handleChange}
          placeholder="e.g. Bin is overflowing, needs urgent collection"
          style={{ ...inputStyle, height: "100px", resize: "vertical" }}
        />

        <label style={{ fontWeight: "bold", display: "block", marginBottom: "6px" }}>
          Estimated Fill Level: <span style={{ color: "#e74c3c" }}>{form.fill_level}%</span>
        </label>
        <input type="range" name="fill_level" min="0" max="100" value={form.fill_level}
          onChange={handleChange}
          style={{ width: "100%", marginBottom: "20px" }}
        />

        {status && (
          <div style={{
            padding: "12px 16px", borderRadius: "8px", marginBottom: "16px",
            background: status.type === "success" ? "#eafaf1" : "#fdecea",
            color: status.type === "success" ? "#1e8449" : "#e74c3c",
            border: `1px solid ${status.type === "success" ? "#2ecc71" : "#e74c3c"}`
          }}>
            {status.text}
          </div>
        )}

        <button
          onClick={handleSubmit}
          disabled={loading}
          style={{
            background: loading ? "#aaa" : "linear-gradient(135deg, #1a5276, #2e86c1)",
            color: "white", border: "none", padding: "14px 32px",
            borderRadius: "8px", fontSize: "16px", cursor: loading ? "not-allowed" : "pointer",
            width: "100%"
          }}
        >
          {loading ? "⏳ Submitting..." : "📤 Submit Report"}
        </button>
      </div>
    </div>
  );
}
